+}
+
+void display_datasets() {
+    if (dataset_count == 0) {
+        printf("No datasets.\n");
+        return;
+    }
+
+    for (int i = 0; i < dataset_count; i++) {
+        // Show dataset name and count — keeps output compact and readable
+        printf("Dataset %d: %s (%d points)\n",
+               i + 1,
+               datasets[i].variable_name,
+               datasets[i].count);
+
